return $input.all().map(item => {
  const fileName = item.json.name || "";

  // الأنماط المختلفة
  const patterns = [
    { regex: /(.*)\s*Limited Company\.pdf$/i, type: "Limited" },
    { regex: /(.*)\s*personal Company\s*\.pdf$/i, type: "Personal" },
    { regex: /(.*)\s*Tax\s*payers?\.pdf$/i, type: "Taxpayer" }
  ];

  let companyName = fileName;
  let companyType = "Unknown";

  for (const p of patterns) {
    const match = fileName.match(p.regex);
    if (match) {
      companyName = match[1].trim();
      companyType = p.type;
      break;
    }
  }

  // إضافة normalizedName لتسهيل المقارنات
  const normalizedName = companyName
    .toLowerCase()
    .replace(/\s+/g, " ") // مسافة واحدة
    .trim();

  return {
    json: {
      id: item.json.id,
      name: fileName,
      companyName,
      normalizedName,
      companyType
    }
  };
});

